<?php $__env->startSection('content'); ?><div class="container py-5"><h1>Checkout</h1><div class="row g-4"><div class="col-lg-7"><form class="table-card" method="post" action="<?php echo e(route('checkout.store')); ?>"><?php echo csrf_field(); ?><h5>Delivery Address</h5><input class="form-control mb-3" name="name" placeholder="Full name" value="<?php echo e(auth()->user()->name); ?>"><input class="form-control mb-3" name="phone" placeholder="Phone" value="<?php echo e(auth()->user()->phone); ?>"><input class="form-control mb-3" name="email" placeholder="Email" value="<?php echo e(auth()->user()->email); ?>"><select class="form-select mb-3" name="delivery_area"><option value="inside_dhaka">Inside Dhaka - ৳80</option><option value="outside_dhaka">Outside Dhaka - ৳130</option><option value="same_district">Same district/local area - ৳50</option></select><input class="form-control mb-3" name="district" placeholder="District"><input class="form-control mb-3" name="city" placeholder="City/Area"><textarea class="form-control mb-3" name="address_line" placeholder="Full address"></textarea><h5>Payment</h5><select class="form-select mb-3" name="payment_method"><option value="cash_on_delivery">Cash on Delivery</option><option value="bkash">bKash</option><option value="nagad">Nagad</option><option value="card">Card</option></select><input class="form-control mb-3" name="transaction_id" placeholder="Transaction ID for bKash/Nagad"><input class="form-control mb-3" name="coupon_code" placeholder="Coupon code"><button class="btn btn-success">Place Order</button></form></div><div class="col-lg-5"><div class="table-card"><h5>Order Summary</h5><?php ($subtotal=0); ?><?php $__currentLoopData = $cart->items; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $item): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><?php ($subtotal+=$item->quantity*$item->product->selling_price); ?><div class="d-flex justify-content-between border-bottom py-2"><span><?php echo e($item->product->name); ?> x <?php echo e($item->quantity); ?></span><strong>৳<?php echo e(number_format($item->quantity*$item->product->selling_price,2)); ?></strong></div><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?><p class="mt-3 mb-0"><strong>Subtotal: ৳<?php echo e(number_format($subtotal,2)); ?></strong></p><small class="text-muted">Delivery charge and coupon discount are calculated after selecting address and coupon.</small></div></div></div></div><?php $__env->stopSection(); ?>

